(window.webpackJsonp=window.webpackJsonp||[]).push([[285],{569:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * @param {number[]} arr\\n */</span>\\n\\n<span class=\\"hljs-keyword\\">var</span> MajorityChecker = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">arr</span>) </span>{\\n  <span class=\\"hljs-keyword\\">this</span>.arr=arr\\n  <span class=\\"hljs-keyword\\">this</span>.memo={}\\n};\\n\\n<span class=\\"hljs-comment\\">/** \\n * @param {number} left \\n * @param {number} right \\n * @param {number} threshold\\n * @return {number}\\n */</span>\\nMajorityChecker.prototype.query = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">left, right, threshold</span>) </span>{\\n  \\n  <span class=\\"hljs-keyword\\">let</span> hash={}\\n  <span class=\\"hljs-keyword\\">if</span>(<span class=\\"hljs-keyword\\">this</span>.memo[left+<span class=\\"hljs-string\\">\' \'</span>+right]!=<span class=\\"hljs-literal\\">null</span>)hash=<span class=\\"hljs-keyword\\">this</span>.memo[left+<span class=\\"hljs-string\\">\' \'</span>+right]\\n  <span class=\\"hljs-keyword\\">else</span>{\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=left;i&lt;=right;i++){\\n      <span class=\\"hljs-keyword\\">if</span>(hash[<span class=\\"hljs-keyword\\">this</span>.arr[i]]==<span class=\\"hljs-literal\\">null</span>)hash[<span class=\\"hljs-keyword\\">this</span>.arr[i]]=<span class=\\"hljs-number\\">1</span>\\n      <span class=\\"hljs-keyword\\">else</span> hash[<span class=\\"hljs-keyword\\">this</span>.arr[i]]++\\n    }\\n      <span class=\\"hljs-keyword\\">this</span>.memo[left+<span class=\\"hljs-string\\">\' \'</span>+right]=hash\\n  }\\n\\n  <span class=\\"hljs-keyword\\">let</span> res=<span class=\\"hljs-literal\\">null</span>\\n  <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> k <span class=\\"hljs-keyword\\">in</span> hash){\\n    <span class=\\"hljs-keyword\\">if</span>(hash[k]&gt;=threshold)<span class=\\"hljs-keyword\\">return</span> +k\\n  }\\n  <span class=\\"hljs-keyword\\">return</span> <span class=\\"hljs-number\\">-1</span>\\n  \\n};\\n\\n<span class=\\"hljs-comment\\">/** \\n * Your MajorityChecker object will be instantiated and called as such:\\n * var obj = new MajorityChecker(arr)\\n * var param_1 = obj.query(left,right,threshold)\\n */</span>\\n</code></pre>\\n"],"titleSlug":"online-majority-element-in-subarray","hasThinking":false,"content":"<p>\u5b9e\u73b0\u4e00\u4e2a&nbsp;<code>MajorityChecker</code>&nbsp;\u7684\u7c7b\uff0c\u5b83\u5e94\u8be5\u5177\u6709\u4e0b\u8ff0\u51e0\u4e2a API\uff1a</p>\\n\\n<ul>\\n\\t<li><code>MajorityChecker(int[] arr)</code>&nbsp;\u4f1a\u7528\u7ed9\u5b9a\u7684\u6570\u7ec4 <code>arr</code>&nbsp;\u6765\u6784\u9020\u4e00\u4e2a <code>MajorityChecker</code> \u7684\u5b9e\u4f8b\u3002</li>\\n\\t<li><code>int query(int left, int right, int threshold)</code>&nbsp;\u6709\u8fd9\u4e48\u51e0\u4e2a\u53c2\u6570\uff1a\\n\\t<ul>\\n\\t\\t<li><code>0 &lt;= left&nbsp;&lt;= right&nbsp;&lt; arr.length</code> \u8868\u793a\u6570\u7ec4&nbsp;<code>arr</code>&nbsp;\u7684\u5b50\u6570\u7ec4\u7684\u957f\u5ea6\u3002</li>\\n\\t\\t<li><code>2 * threshold &gt; right - left + 1</code>\uff0c\u4e5f\u5c31\u662f\u8bf4\u9608\u503c <code>threshold</code>&nbsp;\u59cb\u7ec8\u6bd4\u5b50\u5e8f\u5217\u957f\u5ea6\u7684\u4e00\u534a\u8fd8\u8981\u5927\u3002</li>\\n\\t</ul>\\n\\t</li>\\n</ul>\\n\\n<p>\u6bcf\u6b21\u67e5\u8be2&nbsp;<code>query(...)</code>&nbsp;\u4f1a\u8fd4\u56de\u5728&nbsp;<code>arr[left], arr[left+1], ..., arr[right]</code>&nbsp;\u4e2d\u81f3\u5c11\u51fa\u73b0\u9608\u503c\u6b21\u6570&nbsp;<code>threshold</code>&nbsp;\u7684\u5143\u7d20\uff0c\u5982\u679c\u4e0d\u5b58\u5728\u8fd9\u6837\u7684\u5143\u7d20\uff0c\u5c31\u8fd4\u56de&nbsp;<code>-1</code>\u3002</p>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u793a\u4f8b\uff1a</strong></p>\\n\\n<pre>MajorityChecker majorityChecker = new MajorityChecker([1,1,2,2,1,1]);\\nmajorityChecker.query(0,5,4); // \u8fd4\u56de 1\\nmajorityChecker.query(0,3,3); // \u8fd4\u56de -1\\nmajorityChecker.query(2,3,2); // \u8fd4\u56de 2\\n</pre>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li><code>1 &lt;= arr.length &lt;=&nbsp;20000</code></li>\\n\\t<li><code>1 &lt;= arr[i]&nbsp;&lt;=&nbsp;20000</code></li>\\n\\t<li>\u5bf9\u4e8e\u6bcf\u6b21\u67e5\u8be2\uff0c<code>0 &lt;= left &lt;= right &lt; len(arr)</code></li>\\n\\t<li>\u5bf9\u4e8e\u6bcf\u6b21\u67e5\u8be2\uff0c<code>2 * threshold &gt; right - left + 1</code></li>\\n\\t<li>\u67e5\u8be2\u6b21\u6570\u6700\u591a\u4e3a <code>10000</code></li>\\n</ul>\\n"}')}}]);